import { llamaApiCall } from "../llm/llm.llama.js";
import { geminiApiCall } from "../llm/llm.gemini.js";
import { openAiApiCall } from "../llm/llm.openai.js";
import { AIServiceError } from "../errors/errors.customErr.js";
import { analyzedTweetVar } from "./analysis.schemaModel.js";

//param1: textClaim and param2: tweetId
export async function anaylsisServices(param1, param2) {
  console.log("Inside analysisServices() func");
  //taking all the data generated by artificial intelligence #tip : use Promise.all() to run
  //all three at once
  const dataFromLlamaAI = await llamaApiCall(param1);
  const dataFromOpenAI = await openAiApiCall(param1);
  const dataFromGeminiAI = await geminiApiCall(param1);

  console.log("All LLMs has 'something' responded");

  if (!dataFromLlamaAI && !dataFromOpenAI && !dataFromGeminiAI) {
    throw new AIServiceError("All LLM failed to respond useful data");
  }

  console.log("At least one llm has worked successfully");
  console.log("Pasting the result of the llms: ");

  console.log("This is response from Llama : \n", dataFromLlamaAI);
  console.log("\n\nThis is response from Gpt Oss : \n", dataFromOpenAI);
  console.log("\n\nThis is response from Gemini : \n", dataFromGeminiAI);

  console.log("Moving to the calculation for unified output");

  //function to calculate the final output
  //45% of Llama 4 Scout + 35% of GPT-OSS-120b + 20% of Gemini-3.5-flash
  //parameter: name of the scores
  const toCalc = (parameter) => {
    console.log("Inside toCalc() function");
    let finalVal;

    //if all llm is present
    if (!!dataFromLlamaAI && !!dataFromOpenAI && !!dataFromGeminiAI) {
      console.log("Inside if block of toCalc()");
      finalVal =
        0.45 * dataFromLlamaAI.scores[parameter] +
        0.35 * dataFromOpenAI.scores[parameter] +
        0.2 * dataFromGeminiAI.scores[parameter];
    } else {
      console.log("Inside else block of toCalc()");
      //finding which llm are working to know to perform calculations
      const availableLLMScores = [
        dataFromLlamaAI?.scores?.[parameter],
        dataFromOpenAI?.scores?.[parameter],
        dataFromGeminiAI?.scores?.[parameter],
      ].filter((available) => {
        return available != undefined;
      });

      //calculating the final score by doing average
      finalVal =
        availableLLMScores.reduce((initial, current) => {
          return initial + current;
        }, 0) / availableLLMScores.length;
    }

    console.log("Calculated the final values of scores");
    return finalVal;
  };

  console.log("Calculating the final output to send it to the frontend");
  //writing the logic for getting unified output
  const finalData = {
    finalClaims:
      dataFromOpenAI?.claim ||
      dataFromGeminiAI?.claim ||
      dataFromLlamaAI?.claim,
    finalScores: {
      evidenceStrength: toCalc("evidenceStrength"),
      logicalConsistency: toCalc("logicalConsistency"),
      generalizationRisk: toCalc("generalizationRisk"),
      confirmationBias: toCalc("confirmationBias"),
      nuanceAndContext: toCalc("nuanceAndContext"),
    },
    finalStrength:
      dataFromGeminiAI?.strengths ||
      dataFromLlamaAI?.strengths ||
      dataFromOpenAI?.strengths,
    finalWeakness:
      dataFromGeminiAI?.weaknesses ||
      dataFromLlamaAI?.weaknesses ||
      dataFromOpenAI?.weaknesses,

    finalNuances:
      dataFromGeminiAI?.nuances ||
      dataFromLlamaAI?.nuances ||
      dataFromOpenAI?.nuances,

    finalSummary:
      dataFromGeminiAI?.summary ||
      dataFromLlamaAI?.summary ||
      dataFromOpenAI?.summary,
  };

  console.log("These are the finalised data\n\n", finalData);

  console.log(
    "Saved the crucial data in database if at least one llm answered properly",
  );
  //saving the finalData in database if all llms was present
  console.log("Saving...");
  await analyzedTweetVar.create({
    tweetId: param2,
    claims: finalData.finalClaims,
    scores: {
      evidence_strength: finalData.finalScores.evidenceStrength,
      logical_consistency: finalData.finalScores.logicalConsistency,
      generalization_risk: finalData.finalScores.generalizationRisk,
      confirmation_bias: finalData.finalScores.confirmationBias,
      nuance_and_context: finalData.finalScores.nuanceAndContext,
    },
    strength: finalData.finalStrength,
    weakness: finalData.finalWeakness,
    nuances: finalData.finalNuances,
    summary: finalData.finalSummary,
  });
  console.log("Data successfully saved in database");

  console.log("Returing the value of func");
  return finalData;
}
